    // Precompute the popcount-depth for numbers up to a certain limit
    // Since k can be up to 5, we can precompute for numbers up to 2^20 (which is larger than 10^15)
    const maxLimit = 1 << 20;
    const dp = new Array(maxLimit).fill(0);

    // Function to compute popcount
    function popcount(x) {
        let count = 0;
        while (x) {
            x &= x - 1;
            count++;
        }
        return count;
    }

    // Precompute popcount-depth for numbers up to maxLimit
    for (let x = 1; x < maxLimit; x++) {
        let current = x;
        let depth = 0;
        while (current !== 1) {
            current = popcount(current);
            depth++;
            if (depth > 20) break; // Prevent infinite loop for large numbers
        }
        dp[x] = depth;
    }

    // Count numbers in [1, n] with popcount-depth exactly k
    let count = 0;
    for (let i = 1; i <= n; i++) {
        if (dp[i] === k) {
            count++;
        }
    }

    return count;
}

